scan_linter_check.script:
(function (engine) {

	if (x_snc_codesanity.IsCheckApplicableToRecord())
	{
		var strSource = x_snc_devtools.GetStringValue(engine.rootNode.toSource());
		strSource = x_snc_devtools.ScriptRemoveComments(strSource);

		var strTable = x_snc_devtools.GetStringValue(current.getRecordClassName());
		var bException = false;

		if (strTable == 'sys_script_include')
		{
			var strName = x_snc_devtools.GetStringValue(current.name);
			if (strName == 'ParseJson')
			{
				bException = true;
			}
		}
		if (strTable == 'sys_ui_script')
		{
			var strName = x_snc_devtools.GetStringValue(current.name);
			if (strName == 'x_snc_devtools.ParseJson')
			{
				bException = true;
			}
		}
		if (bException == false)
		{
			if (strSource.indexOf('JSON.parse') != -1)
			{
				engine.finding.increment();
			}			
		}
	}

})(engine);
